class Solution:
    def sumOfDistancesInTree(self, n, edges):
        from collections import deque
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        res = [0] * n
        for src in range(n):
            dist = [-1] * n
            dist[src] = 0
            q = deque([src])
            total = 0
            while q:
                u = q.popleft()
                for w in adj[u]:
                    if dist[w] == -1:
                        dist[w] = dist[u] + 1
                        total += dist[w]
                        q.append(w)
            res[src] = total
        return res

