class Solution:
    def sumOfDistancesInTree(self, n, edges):
        import sys
        sys.setrecursionlimit(100000)
        adj = [[] for _ in range(n)]
        for a, b in edges:
            adj[a].append(b)
            adj[b].append(a)
        count = [1] * n
        ans = [0] * n
        order = []
        parent = [-1] * n
        stack = [0]
        visited = [False] * n
        visited[0] = True
        while stack:
            u = stack.pop()
            order.append(u)
            for w in adj[u]:
                if not visited[w]:
                    visited[w] = True
                    parent[w] = u
                    stack.append(w)
        for u in reversed(order):
            p = parent[u]
            if p != -1:
                count[p] += count[u]
                ans[p] += ans[u] + count[u]
        for u in order:
            p = parent[u]
            if p != -1:
                ans[u] = ans[p] - count[u] + (n - count[u])
        return ans

